	dcn10_update(mmio_base, MPCC_TOP_SEL, 0xf, 0);
	dcn10_update(mmio_base, MPCC_OPP_ID, 0xf, 0);
	dcn10_update(mmio_base, MPCC_UPDATE_LOCK_SEL, 0xf, 0);
	dcn10_update(mmio_base, MPC_OUT_MUX, 0xf, 0);

	/* Linux optc1_enable_optc_clock(), optc1_enable_crtc(), and unblank. */
	dcn10_program_timing(mmio_base, timing);
	dcn10_update(mmio_base, OPTC_INPUT_CLOCK_CONTROL, 0x3, 0x3);
	dcn10_update(mmio_base, OTG_CLOCK_CONTROL, 0x3, 0x3);
	mdelay(1);
	dcn10_update(mmio_base, OPTC_DATA_SOURCE_SELECT, 0x700, 0);
	dcn10_update(mmio_base, VTG_CONTROL, 0x80000000, 0x80000000);
	dcn10_update(mmio_base, OTG_CONTROL, 0x301, 0x301);
	dcn10_update(mmio_base, OTG_BLANK_CONTROL, 0x00010100, 0);
	printk(BIOS_INFO,
	       "ATOMBIOS: DCN1 OTG ctrl=0x%08x blank=0x%08x clock=0x%08x "
	       "input=0x%08x vtg=0x%08x htotal=0x%08x vtotal=0x%08x "
	       "vstartup=0x%08x vupdate=0x%08x vready=0x%08x\n",
	       dcn10_read(mmio_base, OTG_CONTROL),
	       dcn10_read(mmio_base, OTG_BLANK_CONTROL),
	       dcn10_read(mmio_base, OTG_CLOCK_CONTROL),
	       dcn10_read(mmio_base, OPTC_INPUT_CLOCK_CONTROL),
	       dcn10_read(mmio_base, VTG_CONTROL),
	       dcn10_read(mmio_base, OTG_H_TOTAL),
	       dcn10_read(mmio_base, OTG_V_TOTAL),
	       dcn10_read(mmio_base, OTG_VSTARTUP_PARAM),
	       dcn10_read(mmio_base, OTG_VUPDATE_PARAM),
	       dcn10_read(mmio_base, OTG_VREADY_PARAM));

	dcn10_fill_test_pattern(cpu_address, pitch, width, height);

	/* Linux hubp1_program_surface_flip_and_addr(): high first, low latches. */
	dcn10_write(mmio_base, DCSURF_PRIMARY_ADDRESS_HIGH, gpu_address >> 32);
	dcn10_write(mmio_base, DCSURF_PRIMARY_ADDRESS, gpu_address);

	/* Linux hubp1_set_blank(false). */
	hubp_cntl = dcn10_read(mmio_base, DCHUBP_CNTL);
	hubp_cntl &= ~(HUBP_BLANK_EN | HUBP_DISABLE |
		       HUBP_TTU_DISABLE | HUBP_VTG_SEL_MASK);
	dcn10_write(mmio_base, DCHUBP_CNTL, hubp_cntl);
	mdelay(20);
	printk(BIOS_INFO,
	       "ATOMBIOS: DCN1 HUBP cntl=0x%08x earliest=0x%08x%08x "
	       "address=0x%08x%08x pitch=0x%08x dlg=0x%08x/0x%08x/0x%08x\n",
	       dcn10_read(mmio_base, DCHUBP_CNTL),
	       dcn10_read(mmio_base, DCSURF_EARLIEST_INUSE_HIGH),
	       dcn10_read(mmio_base, DCSURF_EARLIEST_INUSE),
	       dcn10_read(mmio_base, DCSURF_PRIMARY_ADDRESS_HIGH),
	       dcn10_read(mmio_base, DCSURF_PRIMARY_ADDRESS),
	       dcn10_read(mmio_base, DCSURF_SURFACE_PITCH),
	       dcn10_read(mmio_base, BLANK_OFFSET_0),
	       dcn10_read(mmio_base, DST_DIMENSIONS),
	       dcn10_read(mmio_base, REF_FREQ_TO_PIX_FREQ));

	*pitch_bytes = pitch;
	printk(BIOS_INFO,
	       "ATOMBIOS: DCN1 scanout %ux%u pitch=%u GPU=0x%016llx CPU=%p\n",
	       width, height, pitch, (unsigned long long)gpu_address, cpu_address);
	return 0;
}

